'use strict';

/**
 * Module dependencies.
 */

var express = require('./lib/express');

/**
 * Expose the express constructor as the module interface.
 */

module.exports = express;

/**
 * Expose the prototypes.
 */

module.exports.application = express.application;
module.exports.request = express.request;
module.exports.response = express.response;

/**
 * Expose constructors.
 */

module.exports.Route = express.Route;
module.exports.Router = express.Router;

/**
 * Expose middleware.
 */

module.exports.json = express.json;
module.exports.query = express.query;
module.exports.raw = express.raw;
module.exports.static = express.static;
module.exports.text = express.text;
module.exports.urlencoded = express.urlencoded;

/**
 * Expose the mime lookup function.
 */

module.exports.mime = express.mime;